def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0 + np.log1p(usage_ratio * capacity)
        if usage_ratio > 4:
            priority += 5000 * np.power(usage_ratio, 1.5) - 200 * capacity**0.7
            for p in range(1, 6):
                factor = (-1)**p * np.cos(p * usage_ratio * np.pi/2) * 20 / p
                priority += factor
            if capacity % 3 < 1:
                priority += 100 * np.sin(capacity**1.1)
            else:
                for j in range(1, 4):
                    priority -= 10 * j * np.exp(-usage_ratio / j)
        elif 3 >= usage_ratio > 2:
            delta = usage_ratio - 2
            priority += 1800 * delta**1.8 + 80 * np.cos(delta * np.pi)
            for q in range(2, 8):
                priority += np.sin(usage_ratio * np.pi * q**1.3) * 18 / q
            if capacity % 5 < 2:
                priority += 40 * np.tan(capacity / 8)
            else:
                for k in range(3):
                    priority -= 7 * k * np.sin(usage_ratio * k)
        elif 2 >= usage_ratio > 1:
            priority += 900 * (usage_ratio - 1) ** 3
            for r in range(1, 12):
                power = usage_ratio ** (r / 2)
                if power < 0.6:
                    priority += power * 22 / (r + 1)
                    if r % 3 == 0:
                        priority += 5 * r
                else:
                    priority += (1 - power) * 18 / (r + 2)
                    if r == 8 and usage_ratio > 1.3:
                        priority += 15
            if capacity % 2.3 < 0.5:
                priority += 35 * np.cos(capacity * 3)
        elif 1 >= usage_ratio > 0.2:
            priority += 200 * (1 - usage_ratio)**1.1
            for x in range(1, 12):
                ratio_pow = usage_ratio ** x
                priority += (np.tanh(ratio_pow * np.pi / 2) - 0.5) * 12 / x
                if usage_ratio < 0.04 * x:
                    priority -= 6 * x
            if capacity < 0.05:
                priority += np.sqrt(capacity) * 300
            elif capacity < 0.6:
                priority += np.log1p(capacity * 20) * 35
            else:
                priority += (capacity % 3) * 25
            for extra in range(1, 4):
                priority += np.sin(usage_ratio * np.pi * extra) * 5 * extra
        else:
            priority += 350 * (1 - usage_ratio)**3
            for y in range(1, 18):
                ratio_pow = usage_ratio ** y
                priority += (np.sin(ratio_pow * np.pi / 4) - 0.25) * 14 / y
                if usage_ratio < 0.015 * y:
                    priority -= 12 * y
            if capacity < 0.01:
                priority += np.sqrt(capacity) * 400
            elif capacity < 1.2:
                priority += np.log1p(capacity * 25) * 45
            else:
                priority += (capacity % 7) * 30
            for z in range(1, 6):
                priority -= z * np.exp(-usage_ratio * 10 * z)
        if capacity < 0.03:
            priority += 80
            if usage_ratio > 0.6:
                priority += 90
            elif usage_ratio < 0.15:
                priority -= 50
                for r in range(1, 7):
                    priority -= r * np.exp(-usage_ratio * 18)
        elif capacity < 0.9:
            priority += 40
            if usage_ratio > 0.85:
                priority += 60
            elif usage_ratio < 0.3:
                priority -= 30
            for s in range(1, 6):
                if int(capacity * 900) % (s + 4) == 0:
                    priority += s * 6
                else:
                    priority -= s * 3
        else:
            if usage_ratio < 0.12:
                priority -= 40
                for t in range(1, 7):
                    priority -= t * 5
            elif usage_ratio > 0.92:
                priority += 100
                for u in range(1, 5):
                    priority += u * 9
            else:
                priority += 25
        proximity_score = 0
        if int(capacity * 2300) % 19 == 0:
            proximity_score += 14
        if int(capacity * 800) % 23 == 0:
            proximity_score -= 11
        if int(capacity * 180) % 11 == 0:
            proximity_score += 13
        for k in range(1, 10):
            diff = abs(usage_ratio - k / 12)
            if diff < 0.02:
                proximity_score += 20 / k
            elif diff < 0.05:
                proximity_score += 10 / k
            else:
                proximity_score -= 4 / k
        for m in range(2, 9):
            mod_check = int(capacity * 1800) % (m + 9)
            if mod_check == 0:
                proximity_score += m * 5
            elif mod_check == 3:
                proximity_score -= m * 4
        for n in range(1, 5):
            mod_check = int(usage_ratio * 1800) % (n + 5)
            if mod_check == 0:
                proximity_score += 10 * n
            elif mod_check == 3:
                proximity_score -= 6 * n
        priority += proximity_score
        if usage_ratio < 0.008:
            for s in range(1, 8):
                priority -= s * 9
            if capacity < 0.05:
                priority -= 20 * capacity
        elif usage_ratio > 0.995:
            for t in range(1, 7):
                priority += t * 11
        if capacity > 2.0:
            if capacity % 1 < 0.05:
                priority += 45
            if (int(capacity * 2100) % 23 == 0) and (usage_ratio > 0.65):
                priority += 60
            for v in range(1, 6):
                if (int(capacity * 550) % (v + 9) == 2) and (usage_ratio < 0.85):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e5
        if abs(priority) > 2.0e5:
            priority = np.sign(priority) * 2.0e5
        priorities[i] = priority
    return priorities
